import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../hooks/usecart';
import { ChevronLeft, AlertTriangle, Check, Loader2, ShieldCheck } from 'lucide-react';

const CheckoutPage = () => {
  const navigate = useNavigate();
  const { items = [] } = useCart();

  const validItems = items.filter(item => item && item.productId && String(item.productId) !== 'undefined');

  useEffect(() => {
    if (validItems.length === 0) {
      navigate('/cart');
    }
  }, [validItems, navigate]);

  // ========================================================
  // 🚀 FORM STATES
  // ========================================================
  const [isBillingSame, setIsBillingSame] = useState(true);

  const [shipping, setShipping] = useState({
    fullName: '', phone: '', address1: '', address2: '', pincode: '', city: '', state: ''
  });

  const [billing, setBilling] = useState({
    fullName: '', email: '', phone: '', pincode: '', city: '', state: '', address1: '', address2: '', landmark: ''
  });

  // Validation Modal State (Centered Premium Modal)
  const [showModal, setShowModal] = useState(false);
  const [modalMessage, setModalMessage] = useState('');

  const [fetchingPin, setFetchingPin] = useState({ shipping: false, billing: false });

  // ========================================================
  // 🚀 API: AUTO-FETCH PINCODE
  // ========================================================
  const fetchLocation = async (pin, type) => {
    if (pin.length !== 6) return;
    setFetchingPin(prev => ({ ...prev, [type]: true }));

    try {
      const response = await fetch(`https://api.postalpincode.in/pincode/${pin}`);
      const data = await response.json();

      if (data && data[0] && data[0].Status === 'Success' && data[0].PostOffice?.length > 0) {
        const po = data[0].PostOffice[0];
        const fetchedCity = po.District || po.Block || po.Region || '';
        const fetchedState = po.State || '';

        if (type === 'shipping') {
          setShipping(prev => ({ ...prev, city: fetchedCity, state: fetchedState }));
        } else {
          setBilling(prev => ({ ...prev, city: fetchedCity, state: fetchedState }));
        }
      }
    } catch (error) {
      console.error("Error fetching pincode:", error);
    } finally {
      setFetchingPin(prev => ({ ...prev, [type]: false }));
    }
  };

  useEffect(() => {
    const pin = shipping.pincode.replace(/\D/g, '');
    const timeoutId = setTimeout(() => { if (pin.length === 6) fetchLocation(pin, 'shipping'); }, 400);
    return () => clearTimeout(timeoutId);
  }, [shipping.pincode]);

  useEffect(() => {
    const pin = billing.pincode.replace(/\D/g, '');
    const timeoutId = setTimeout(() => { if (pin.length === 6) fetchLocation(pin, 'billing'); }, 400);
    return () => clearTimeout(timeoutId);
  }, [billing.pincode]);

  // ========================================================
  // 🚀 MATH CALCULATIONS
  // ========================================================
  const totalItems = validItems.reduce((acc, item) => acc + (Number(item.quantity) || 1), 0);

  let totalDiscountedPrice = 0;
  let totalMrp = 0;

  validItems.forEach(item => {
    const qty = Number(item.quantity) || 1;
    const price = Number(item.price) || 0;
    const mrp = Number(item.compare_price || item.mrp) || Math.round(price * 1.25);
    totalDiscountedPrice += (price * qty);
    totalMrp += (mrp * qty);
  });

  const baseDiscount = Math.max(0, totalMrp - totalDiscountedPrice);
  const couponDiscount = 10750; // Visual demo coupon 
  const finalPayable = Math.max(0, totalDiscountedPrice - couponDiscount);
  const totalSaved = baseDiscount + couponDiscount;

  // Handlers
  const handleShippingChange = (e) => {
    const { name, value } = e.target;
    if (name === 'pincode' && value && !/^\d*$/.test(value)) return;
    setShipping(prev => ({ ...prev, [name]: value }));
  };

  const handleBillingChange = (e) => {
    const { name, value } = e.target;
    if (name === 'pincode' && value && !/^\d*$/.test(value)) return;
    setBilling(prev => ({ ...prev, [name]: value }));
  };

  // ========================================================
  // 🚀 PROCEED TO PAYMENT (Fixed Navigation)
  // ========================================================
  const handleContinuePayment = () => {
    let hasError = false;

    // 1. Validate Shipping
    const reqShipping = ['fullName', 'phone', 'address1', 'pincode', 'city', 'state'];
    reqShipping.forEach(field => {
      if (!shipping[field].trim()) { hasError = true; }
    });

    if (shipping.phone && shipping.phone.replace(/\D/g, '').length < 10) hasError = true;
    if (shipping.pincode && shipping.pincode.replace(/\D/g, '').length !== 6) hasError = true;

    // 2. Validate Billing (if different)
    if (!isBillingSame) {
      const reqBilling = ['fullName', 'email', 'phone', 'address1', 'pincode', 'city', 'state'];
      reqBilling.forEach(field => {
        if (!billing[field].trim()) { hasError = true; }
      });
      if (billing.phone && billing.phone.replace(/\D/g, '').length < 10) hasError = true;
      if (billing.pincode && billing.pincode.replace(/\D/g, '').length !== 6) hasError = true;
    }

    // Trigger Centered Modal on Error
    if (hasError) {
      setModalMessage('Please fill in all required details to proceed with your order.');
      setShowModal(true);
      return;
    }

    // 🚀 ACTUAL NAVIGATION TO PAYMENT PAGE
    navigate('/payment', {
      state: {
        shipping,
        billing: isBillingSame ? shipping : billing,
        totalAmount: finalPayable,
        orderItems: validItems
      }
    });
  };

  // ========================================================
  // 🚀 CLEAN INPUT CLASS (No Ghost Lines, No Red Outlines)
  // ========================================================
  const getInputClass = () => `
    w-full text-[14px] rounded-lg px-4 py-3 outline-none focus:outline-none focus:ring-0 transition-colors placeholder:text-gray-400
    bg-white border border-gray-300 hover:border-gray-400 focus:border-[#f97316] text-gray-900 shadow-none
  `;

  return (
    <div className="bg-[#f8f9fa] min-h-screen py-8 md:py-10 font-sans relative">

      {/* ========================================================
          🚀 THE EXACT CENTERED MODAL
          ======================================================== */}
      {showModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-gray-900/40 backdrop-blur-sm transition-all duration-300">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-sm p-8 transform transition-all flex flex-col items-center text-center animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 bg-[#fef2f2] text-red-500 rounded-full flex items-center justify-center mb-5">
              <AlertTriangle size={28} strokeWidth={1.5} />
            </div>
            <h3 className="text-[20px] font-bold text-gray-900 mb-2 tracking-tight">Missing Information</h3>
            <p className="text-[14px] text-gray-500 mb-8 leading-relaxed px-2">
              {modalMessage}
            </p>
            <button
              onClick={() => setShowModal(false)}
              className="w-full bg-[#0f172a] text-white font-bold py-3.5 rounded-xl hover:bg-gray-800 transition-all shadow-[0_8px_20px_rgba(15,23,42,0.2)] outline-none focus:outline-none focus:ring-0 border-none select-none"
            >
              GOT IT
            </button>
          </div>
        </div>
      )}

      <div className="container mx-auto px-4 max-w-6xl">
        <div className="mb-6">
          <button
            onClick={() => navigate('/cart')}
            className="inline-flex items-center text-sm font-bold text-[#f97316] hover:text-[#cf6627] transition-colors group outline-none focus:outline-none focus:ring-0 border-none bg-transparent select-none"
            style={{ WebkitTapHighlightColor: 'transparent' }}
          >
            <ChevronLeft size={18} className="group-hover:-translate-x-1 transition-transform" />
            Return to Cart
          </button>
        </div>

        <div className="flex items-center mb-6">
          <h1 className="text-[28px] font-black text-[#1e293b] tracking-tight">Checkout</h1>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

          {/* ========================================================
              LEFT COLUMN: FORMS
              ======================================================== */}
          <div className="lg:col-span-7 flex flex-col gap-6">

            {/* SHIPPING ADDRESS */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 md:p-8">
              <div className="flex items-center gap-3 mb-8">
                <div className="bg-[#6f4f36] text-white w-8 h-8 flex items-center justify-center rounded-full">
                  <span className="font-bold text-sm">1</span>
                </div>
                <h2 className="text-[18px] font-bold text-[#1e293b]">Shipping Address</h2>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-5 gap-y-6">
                <div className="relative md:col-span-1">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Full Name *</label>
                  <input type="text" name="fullName" value={shipping.fullName} onChange={handleShippingChange} className={getInputClass()} placeholder="e.g. John Doe" />
                </div>

                <div className="relative md:col-span-1">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Phone Number *</label>
                  <input type="tel" name="phone" value={shipping.phone} onChange={handleShippingChange} maxLength="10" className={getInputClass()} placeholder="e.g. 9876543210" />
                </div>

                <div className="relative md:col-span-2">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Address Line 1 *</label>
                  <input type="text" name="address1" value={shipping.address1} onChange={handleShippingChange} className={getInputClass()} placeholder="House No., Building Name, Street" />
                </div>

                <div className="relative md:col-span-2">
                  <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Address Line 2 (Optional)</label>
                  <input type="text" name="address2" value={shipping.address2} onChange={handleShippingChange} className={getInputClass()} placeholder="Locality, Area, Landmark" />
                </div>

                {/* Pincode Auto-fetch row */}
                <div className="md:col-span-2 grid grid-cols-1 sm:grid-cols-3 gap-4 md:gap-5">
                  <div className="relative">
                    <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Pincode *</label>
                    <div className="relative">
                      <input type="text" name="pincode" value={shipping.pincode} onChange={handleShippingChange} maxLength="6" className={getInputClass()} placeholder="500001" />
                      {fetchingPin.shipping && <div className="absolute right-3 top-1/2 -translate-y-1/2"><Loader2 size={18} className="text-[#f97316] animate-spin" /></div>}
                    </div>
                  </div>

                  <div className="relative">
                    <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">City *</label>
                    <input type="text" name="city" value={shipping.city} onChange={handleShippingChange} className={getInputClass()} placeholder="City" />
                  </div>

                  <div className="relative">
                    <label className="block text-[11px] font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">State *</label>
                    <input type="text" name="state" value={shipping.state} onChange={handleShippingChange} className={getInputClass()} placeholder="State" />
                  </div>
                </div>
              </div>
            </div>

            {/* BILLING TOGGLE BOX */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
              <label className="flex items-center gap-3 cursor-pointer group w-max outline-none" style={{ WebkitTapHighlightColor: 'transparent' }}>
                <div className={`w-[18px] h-[18px] flex items-center justify-center rounded-[3px] transition-colors ${isBillingSame ? 'bg-[#f97316] border-[#f97316]' : 'bg-white border border-gray-300'}`}>
                  {isBillingSame && <Check size={14} className="text-white" strokeWidth={3} />}
                </div>
                <input
                  type="checkbox"
                  className="hidden"
                  checked={isBillingSame}
                  onChange={() => setIsBillingSame(!isBillingSame)}
                />
                <span className="text-[15px] text-[#1e293b] select-none font-medium">Billing address is same as the Shipping address</span>
              </label>

              {/* EXPANDING BILLING FORM */}
              <div className={`transition-all duration-500 ease-in-out overflow-hidden ${isBillingSame ? 'max-h-0 opacity-0' : 'max-h-[1200px] opacity-100 mt-6 border-t border-gray-200 pt-6'}`}>
                <h3 className="text-[16px] font-bold text-[#1e293b] mb-6">Add billing address</h3>

                <div className="flex flex-col gap-5">
                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-center gap-2 md:gap-4">
                    <label className="text-[13px] text-gray-700 font-medium">Full Name <span className="text-red-500">*</span></label>
                    <input type="text" name="fullName" value={billing.fullName} onChange={handleBillingChange} className={getInputClass()} placeholder="Name*" />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-center gap-2 md:gap-4">
                    <label className="text-[13px] text-gray-700 font-medium">Email <span className="text-red-500">*</span></label>
                    <input type="email" name="email" value={billing.email} onChange={handleBillingChange} className={getInputClass()} placeholder="Email Address*" />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-center gap-2 md:gap-4">
                    <label className="text-[13px] text-gray-700 font-medium">Mobile No. <span className="text-red-500">*</span></label>
                    <input type="tel" name="phone" value={billing.phone} onChange={handleBillingChange} maxLength="10" className={getInputClass()} placeholder="Mobile No.*" />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-start md:items-center gap-2 md:gap-4">
                    <label className="text-[13px] text-gray-700 font-medium mt-3 md:mt-0">Pincode <span className="text-red-500">*</span></label>
                    <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                      <div className="relative">
                        <input type="text" name="pincode" value={billing.pincode} onChange={handleBillingChange} maxLength="6" className={getInputClass()} placeholder="Pin Code*" />
                        {fetchingPin.billing && <div className="absolute right-3 top-1/2 -translate-y-1/2"><Loader2 size={18} className="text-[#f97316] animate-spin" /></div>}
                      </div>
                      <input type="text" name="city" value={billing.city} onChange={handleBillingChange} className={getInputClass()} placeholder="City" />
                      <input type="text" name="state" value={billing.state} onChange={handleBillingChange} className={getInputClass()} placeholder="State" />
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-center gap-2 md:gap-4">
                    <label className="text-[13px] text-gray-700 font-medium">Society Address <span className="text-red-500">*</span></label>
                    <input type="text" name="address1" value={billing.address1} onChange={handleBillingChange} className={getInputClass()} placeholder="Flat, House no., Building, Company, Apartment*" />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-center gap-2 md:gap-4">
                    <label className="text-[13px] text-gray-700 font-medium">Area Address <span className="text-red-500">*</span></label>
                    <input type="text" name="address2" value={billing.address2} onChange={handleBillingChange} className={getInputClass()} placeholder="Area, Street, Sector, Village*" />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-[160px_1fr] items-center gap-2 md:gap-4">
                    <label className="text-[13px] text-gray-700 font-medium">Landmark</label>
                    <input type="text" name="landmark" value={billing.landmark} onChange={handleBillingChange} className={getInputClass()} placeholder="Landmark (optional)" />
                  </div>
                </div>
              </div>
            </div>

          </div>

          {/* ========================================================
              RIGHT COLUMN: ORDER SUMMARY
              ======================================================== */}
          <div className="lg:col-span-5 flex flex-col gap-5 md:sticky md:top-28">

            {/* Box 1: Items List */}
            <div className="bg-white border border-gray-200 shadow-sm overflow-hidden flex flex-col rounded-xl">
              <div className="p-4 border-b border-gray-200 bg-white">
                <h3 className="text-[18px] text-[#333333] font-medium tracking-wide">Order Summary</h3>
              </div>

              <div className="p-4 bg-white flex flex-col gap-5 max-h-[300px] overflow-y-auto custom-scrollbar">
                {validItems.map((item, index) => {
                  const itemQty = Number(item.quantity) || 1;
                  return (
                    <div key={index} className="flex items-start gap-4">
                      <div className="w-[90px] h-[70px] bg-gray-50 border border-gray-200 shrink-0 flex items-center justify-center overflow-hidden rounded-md">
                        <img src={item.image || 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=200&q=80'} alt={item.name} className="w-full h-full object-cover" onError={(e) => { e.target.onerror = null; e.target.src = 'https://images.unsplash.com/photo-1493663284031-b7e3aefcae8e?w=200&q=80'; }} />
                      </div>
                      <div className="flex-1 min-w-0 pt-0.5">
                        <h4 className="text-[15px] text-[#555555] font-normal leading-snug mb-2">{item.name || 'Premium Item'}</h4>
                        <p className="text-[13px] text-[#333333] mb-0.5"><span className="font-bold">SKU</span> : {item.variantId || item.productId || 'N/A'}</p>
                        <p className="text-[13px] text-[#333333]"><span className="font-bold">Quantity</span> : {itemQty}</p>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Box 2: Price Details */}
            <div className="bg-white border border-gray-200 shadow-sm overflow-hidden flex flex-col rounded-xl">
              <div className="p-4 border-b border-gray-200 bg-white">
                <h3 className="text-[16px] text-[#333333] font-medium tracking-wide">Price Detail <span className="text-[#888888] text-[14px]">({totalItems} Items)</span></h3>
              </div>

              <div className="p-4 space-y-4 bg-white">
                <div className="flex justify-between items-center text-[15px]">
                  <span className="text-[#333333] font-bold">MRP</span>
                  <span className="text-[#333333] font-bold">₹{totalMrp.toLocaleString('en-IN')}</span>
                </div>

                {baseDiscount > 0 && (
                  <div className="flex justify-between items-center text-[15px]">
                    <span className="text-[#333333] font-bold">Discount</span>
                    <span className="text-[#22c55e]">- ₹{baseDiscount.toLocaleString('en-IN')}</span>
                  </div>
                )}

                <div className="flex justify-between items-center text-[15px]">
                  <span className="text-[#333333] font-bold">Coupon (SUMMER26)</span>
                  <span className="text-[#22c55e]">- ₹{couponDiscount.toLocaleString('en-IN')}</span>
                </div>
              </div>

              <div className="p-4 border-t border-gray-200 bg-white">
                <div className="flex justify-between items-start">
                  <span className="text-[20px] text-[#333333] font-normal">Total Payable</span>
                  <div className="text-right">
                    <span className="text-[20px] text-[#333333] block mb-1">₹{finalPayable.toLocaleString('en-IN')}</span>
                    <span className="text-[11px] text-[#888888] font-normal">Inclusive of all taxes</span>
                  </div>
                </div>
              </div>

              {/* Congratulations Savings Text */}
              {totalSaved > 0 && (
                <div className="px-4 py-3 bg-[#f0fdf4] border-t border-[#bbf7d0]">
                  <p className="text-[14px] text-[#166534] font-medium text-center">
                    Congratulations! You've Just saved ₹{totalSaved.toLocaleString('en-IN')} On Your Order.
                  </p>
                </div>
              )}
            </div>

            {/* 🚀 FIXED: Custom Glow Shadow and Shifted Hover Color */}
            <div className="mt-2 flex flex-col gap-3">
              <button
                onClick={handleContinuePayment}
                className="w-full bg-[#e87831] text-white py-4 rounded-lg font-bold tracking-wider hover:bg-[#cf6627] active:scale-[0.98] transition-all duration-300 shadow-[0_4px_14px_rgba(232,120,49,0.4)] hover:shadow-[0_6px_20px_rgba(232,120,49,0.5)] outline-none focus:outline-none focus:ring-0 select-none border-none text-[15px]"
              >
                SAVE AND CONTINUE
              </button>
              <p className="text-[11px] text-center text-gray-500">
                By continuing, I agree to the <span className="text-[#e87831] cursor-pointer hover:underline">Terms of Use</span> & <span className="text-[#e87831] cursor-pointer hover:underline">Privacy Policy</span>
              </p>
            </div>

            <div className="flex items-center justify-center gap-2 text-[12px] text-gray-500 font-medium pt-2 pb-4">
              <ShieldCheck size={16} className="text-[#16a34a]" />
              <span>100% Safe & Secure Checkout</span>
            </div>

          </div>

        </div>
      </div>

      <style jsx="true">{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e5e7eb; border-radius: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #d1d5db; }
      `}</style>
    </div>
  );
};

export default CheckoutPage;
